#include<bits/stdc++.h>
using namespace std;
long long n,m,q,s1[100010],s2[100010];
long long lowbit(long long x)
{
	return x&-x;
}
void update(long long s[],long long x,long long k)
{
	for(long long i=x;i<=100000;i+=lowbit(i))
	{
		s[i]+=k;
	}
}
long long sum(long long s[],long long x)
{
	long long ans=0;
	for(long long i=x;i;i-=lowbit(i))
	{
		ans+=s[i];
	}
	return ans;
}
int main()
{
    scanf("%lld%lld%lld",&n,&m,&q);
    for(long long i=1;i<=q;i++)
    {
        long long op;
        scanf("%lld",&op);
        if(op==1)
        {
            long long x,y;
            scanf("%lld%lld",&x,&y);
            update(s1,x,((sum(s1,x)-sum(s1,x-1))==0?1:-1));
            update(s2,y,((sum(s2,y)-sum(s2,y-1))==0?1:-1));
        }
        else
        {
            long long ax,ay,bx,by;
            scanf("%lld%lld%lld%lld",&ax,&ay,&bx,&by);
            long long n1=bx-ax+1,n2=sum(s1,bx)-sum(s1,ax-1),m1=by-ay+1,m2=sum(s2,by)-sum(s2,ay-1);
            printf("%lld\n",n1*m2+n2*m1-2*n2*m2);
        }
    }
    return 0;
}
